  result: any,
  query: string
): RetrievalFact {
  const now = new Date().toISOString();
  return {
    id: nextFactId(domain),
    source: {
      id: `tool:${toolName}`,
      type: "tool",
      name: toolName,
      freshness: "live",
      timestamp: now,
